struct Node {
    int data;           // Data member to store value
    struct Node *next;  // Self-referential pointer to next node
};

int main() {
    struct Node *head = NULL;  // Head pointer initialized to NULL
    struct Node *newNode;

    // Allocate memory for first node
    newNode = (struct Node*)malloc(sizeof(struct Node));

    // Check if malloc succeeded
    if (newNode == NULL) {
        printf("Memory allocation failed\n");
        return 1;
    }

    // Assign data and set next pointer
    newNode->data = 10;
    newNode->next = NULL;
    head = newNode;  // Head now points to first node

    printf("Node data: %d\n", head->data);

    return 0;
}

#include <stdio.h>
#include <stdlib.h>

struct Node {
    int data;
    struct Node *next;
};

// Function to insert at beginning
struct Node* insertAtBeginning(struct Node *head, int value) {
    // Allocate memory for new node
    struct Node *newNode = (struct Node*)malloc(sizeof(struct Node));

    // Check for allocation failure
    if (newNode == NULL) {
        printf("Memory allocation failed\n");
        return head;
    }

    // Assign data to new node
    newNode->data = value;

    // New node points to current head
    newNode->next = head;

    // Head now points to new node
    return newNode;
}

// Function to display list
void display(struct Node *head) {
    struct Node *temp = head;
    while (temp != NULL) {
        printf("%d -> ", temp->data);
        temp = temp->next;
    }
    printf("NULL\n");
}

int main() {
    struct Node *head = NULL;

    // Insert elements at beginning
    head = insertAtBeginning(head, 30);
    head = insertAtBeginning(head, 20);
    head = insertAtBeginning(head, 10);

    display(head);  // Output: 10 -> 20 -> 30 -> NULL

    return 0;
}

#include <stdio.h>
#include <stdlib.h>

struct Node {
    int data;
    struct Node *next;
};

// Function to delete node with given value
struct Node* deleteNode(struct Node *head, int value) {
    // Case 1: Empty list
    if (head == NULL) {
        printf("List is empty\n");
        return NULL;
    }

    // Case 2: Delete head node
    if (head->data == value) {
        struct Node *temp = head;
        head = head->next;  // Move head to next node
        free(temp);         // Free old head memory
        return head;
    }

    // Case 3: Delete from middle or end
    struct Node *current = head;
    struct Node *prev = NULL;

    while (current != NULL && current->data != value) {
        prev = current;
        current = current->next;
    }

    // If value not found
    if (current == NULL) {
        printf("Value %d not found in list\n", value);
        return head;
    }

    // Unlink node and free memory
    prev->next = current->next;
    free(current);

    return head;
}

int main() {
    struct Node *head = NULL;
    // Create list: 10 -> 20 -> 30 -> NULL
    // (code to create list omitted for brevity)

    head = deleteNode(head, 20);  // Deletes node with value 20

    return 0;
}

#include <stdio.h>
#include <stdlib.h>

// Doubly linked list node structure
struct DNode {
    struct DNode *prev;  // Pointer to previous node
    int data;            // Data member
    struct DNode *next;  // Pointer to next node
};

// Function to create a new doubly linked list node
struct DNode* createNode(int value) {
    struct DNode *newNode = (struct DNode*)malloc(sizeof(struct DNode));

    if (newNode == NULL) {
        printf("Memory allocation failed\n");
        return NULL;
    }

    newNode->prev = NULL;
    newNode->data = value;
    newNode->next = NULL;

    return newNode;
}

// Function to insert at end of doubly linked list
struct DNode* insertAtEnd(struct DNode *head, int value) {
    struct DNode *newNode = createNode(value);

    if (head == NULL) {
        return newNode;  // New node becomes head
    }

    // Traverse to last node
    struct DNode *temp = head;
    while (temp->next != NULL) {
        temp = temp->next;
    }

    // Link the new node
    temp->next = newNode;
    newNode->prev = temp;

    return head;
}

// Function to traverse forward
void displayForward(struct DNode *head) {
    struct DNode *temp = head;
    while (temp != NULL) {
        printf("%d <-> ", temp->data);
        temp = temp->next;
    }
    printf("NULL\n");
}

// Function to traverse backward
void displayBackward(struct DNode *head) {
    if (head == NULL) return;

    // Go to last node
    struct DNode *temp = head;
    while (temp->next != NULL) {
        temp = temp->next;
    }

    // Traverse backward using prev pointers
    while (temp != NULL) {
        printf("%d <-> ", temp->data);
        temp = temp->prev;
    }
    printf("NULL\n");
}

int main() {
    struct DNode *head = NULL;

    head = insertAtEnd(head, 10);
    head = insertAtEnd(head, 20);
    head = insertAtEnd(head, 30);

    printf("Forward: ");
    displayForward(head);   // 10 <-> 20 <-> 30 <-> NULL

    printf("Backward: ");
    displayBackward(head);  // 30 <-> 20 <-> 10 <-> NULL

    return 0;
}
